import math

def sigmoid(z: float) -> float:
    result = 1 / (1 + math.exp(-z))
    return round(result, 4)

numpy.code:
import numpy as np

def sigmoid(z: float) -> float:
    result = 1 / (1 + np.exp(-z))
    return round(float(result), 4)

tensorflow.code:
import tensorflow as tf

def sigmoid(z: float) -> float:
    result = tf.math.sigmoid(tf.constant(z, dtype=tf.float32))
    return round(float(result.numpy()), 4)

pytorch.code:
import torch

def sigmoid(z: float) -> float:
    result = torch.sigmoid(torch.tensor(z, dtype=torch.float32))
    return round(result.item(), 4)
